function solve(nums, k) {
    let total = nums.reduce((acc, val) => acc + val, 0);
    let n = nums.length;
    let prefix = [0];
    for (let i = 0; i < n; i++) {
        prefix.push(prefix[i] + nums[i]);
    }

    let dp = new Array(n+1).fill(0);
    let map = new Map();
    map.set(0, 0);

    for (let i = 1; i <= n; i++) {
        dp[i] = dp[i-1];
        let residue = prefix[i] % k;
        if (map.has(residue)) {
            let candidate = prefix[i] + map.get(residue);
            if (candidate > dp[i]) {
                dp[i] = candidate;
            }
        }
        let currentVal = dp[i] - prefix[i];
        if (map.has(residue)) {
            let bestVal = map.get(residue);
            if (currentVal > bestVal) {
                map.set(residue, currentVal);
            }
        } else {
            map.set(residue, currentVal);
        }
    }

    return total - dp[n];
}
```

